// app/javascript/controllers/flash_controller.ts
class FlashController extends Controller {
  static targets = ['message'];
  messageTargetConnected(message) {
    setTimeout(() => {
      this.dismissMessage(message);
    }, 5000);
  }
  dismiss(event) {
    const message = event.currentTarget.closest(
      '[data-flash-target="message"]',
    );
    if (message) {
      this.dismissMessage(message);
    }
  }
  dismissMessage(message) {
    if (!message.isConnected) return;
    message.classList.remove('animate-slide-in');
    message.classList.add('animate-slide-out');
    message.addEventListener(
      'animationend',
      () => {
        message.remove();
      },
      { once: true },
    );
  }
}

// app/javascript/controllers/form_submit_controller.ts
class form_submit_controller_default extends Controller {
  connect() {
    this.element.addEventListener(
      'turbo:submit-start',
      this.#handleSubmitStart,
    );
    this.element.addEventListener('turbo:submit-end', this.#handleSubmitEnd);
  }
  disconnect() {
    this.element.removeEventListener(
      'turbo:submit-start',
      this.#handleSubmitStart,
    );
    this.element.removeEventListener('turbo:submit-end', this.#handleSubmitEnd);
  }
  #handleSubmitStart = (event) => {
    const form = event.target;
    this.#submitButtons(form).forEach((btn) => this.#setLoading(btn, true));
  };
  #handleSubmitEnd = (event) => {
    const detail = event.detail;
    if (detail.success) return;
    const form = event.target;
    this.#submitButtons(form).forEach((btn) => this.#setLoading(btn, false));
  };
  #submitButtons(form) {
    const inside = Array.from(form.querySelectorAll('[type="submit"]'));
    const outside = form.id
      ? Array.from(
          document.querySelectorAll(`[type="submit"][form="${form.id}"]`),
        )
      : [];
    return [...inside, ...outside];
  }
  #setLoading(btn, loading) {
    if (loading) {
      btn.disabled = true;
      btn.dataset.originalHtml = btn.innerHTML;
      btn.innerHTML = `
        <span class="inline-flex items-center gap-2 justify-center">
          <svg class="animate-spin h-4 w-4 shrink-0" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" aria-hidden="true">
            <circle class="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" stroke-width="4"></circle>
            <path class="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span>${btn.textContent?.trim() ?? ''}</span>
        </span>`;
    } else {
      btn.disabled = false;
      btn.innerHTML = btn.dataset.originalHtml ?? btn.innerHTML;
      delete btn.dataset.originalHtml;
    }
  }
}

// app/javascript/controllers/hello_controller.ts
class HelloController extends Controller {
  connect() {
    console.log('Hello World!');
  }
}

// app/javascript/controllers/dropdown_controller.ts
class DropdownController extends Controller {
  static targets = ['menu'];
  boundClose;
  connect() {
    this.boundClose = this.closeOutside.bind(this);
    document.addEventListener('click', this.boundClose);
  }
  disconnect() {
    document.removeEventListener('click', this.boundClose);
  }
  toggle() {
    if (!this.hasMenuTarget) return;
    this.menuTarget.classList.toggle('hidden');
  }
  closeOutside(event) {
    if (!this.hasMenuTarget) return;
    if (this.menuTarget.classList.contains('hidden')) return;
    if (!this.element.contains(event.target)) {
      this.menuTarget.classList.add('hidden');
    }
  }
}

// app/javascript/controllers/mobile_menu_controller.ts
class MobileMenuController extends Controller {
  static targets = ['menu', 'burgerIcon', 'closeIcon'];
  toggle() {
    if (!this.hasMenuTarget) return;
    const isHidden = this.menuTarget.classList.contains('hidden');
    this.menuTarget.classList.toggle('hidden', !isHidden);
    this.burgerIconTarget.classList.toggle('hidden', isHidden);
    this.closeIconTarget.classList.toggle('hidden', !isHidden);
  }
}

// app/javascript/controllers/file_drop_controller.ts
class FileDropController extends Controller {
  static targets = ['dropZone', 'input', 'label'];
  originalLabelText = '';
  connect() {
    this.originalLabelText = this.labelTarget.textContent || '';
  }
  dragOver(event) {
    event.preventDefault();
    this.dropZoneTarget.classList.add(
      'border-indigo-500',
      'bg-indigo-50',
      'dark:bg-indigo-900/20',
    );
  }
  dragLeave(event) {
    event.preventDefault();
    this.removeHighlight();
  }
  drop(event) {
    event.preventDefault();
    this.removeHighlight();
    const files = event.dataTransfer?.files;
    if (files && files.length > 0) {
      this.inputTarget.files = files;
      this.updateLabel(files);
      this.inputTarget.dispatchEvent(new Event('change', { bubbles: true }));
    }
  }
  openFileDialog() {
    this.inputTarget.click();
  }
  fileSelected() {
    const files = this.inputTarget.files;
    if (files && files.length > 0) {
      this.updateLabel(files);
    }
  }
  removeHighlight() {
    this.dropZoneTarget.classList.remove(
      'border-indigo-500',
      'bg-indigo-50',
      'dark:bg-indigo-900/20',
    );
  }
  updateLabel(files) {
    this.labelTarget.textContent = Array.from(files)
      .map((f) => f.name)
      .join(', ');
    this.labelTarget.classList.add(
      'text-indigo-600',
      'dark:text-indigo-400',
      'font-medium',
    );
  }
}

// app/javascript/controllers/turbo_modal_controller.ts
class TurboModalController extends Controller {
  static targets = ['overlay'];
  hasChildren() {
    return this.element.hasAttribute('data-child-modal-id');
  }
  close() {
    this.overlayTarget.classList.add('hidden');
    if (!this.hasChildren()) {
      this.element.remove();
    }
  }
  closeBackground(event) {
    if (event.target === this.overlayTarget) {
      this.close();
    }
  }
}

