// app/javascript/controllers/morph_protection_controller.ts
class morph_protection_controller_default extends Controller {
  connect() {
    this.preventMorph = this.preventMorph.bind(this);
    document.addEventListener('turbo:before-morph-element', this.preventMorph);
  }
  disconnect() {
    document.removeEventListener(
      'turbo:before-morph-element',
      this.preventMorph,
    );
  }
  preventMorph(event) {
    const customEvent = event;
    if (this.element !== customEvent.target) return;
    const newElement = customEvent.detail?.newElement;
    if (
      !newElement ||
      newElement.querySelector('[data-controller~="model-viewer"]')
    ) {
      customEvent.preventDefault();
    }
  }
}

