// app/javascript/controllers/select_option_controller.ts
var SELECTED = ['!border-green-500', '!bg-green-50'];
var UNSELECTED = [
  'border-gray-200',
  'bg-white',
  'hover:border-gray-300',
  'hover:bg-gray-50',
];

class SelectOptionController extends Controller {
  connect() {
    this.updateCard();
  }
  onChange(event) {
    const radio = event.target;
    document
      .querySelectorAll(`input[type="radio"][name="${CSS.escape(radio.name)}"]`)
      .forEach((r) => {
        const label = r.closest('label');
        if (!label) return;
        const card = label.querySelector('.select-option-card');
        if (!card) return;
        this.setCardState(card, r.checked);
      });
  }
  updateCard() {
    const radio = this.element.querySelector('input[type="radio"]');
    if (!radio) return;
    const card = this.element.querySelector('.select-option-card');
    if (!card) return;
    this.setCardState(card, radio.checked);
  }
  setCardState(card, checked) {
    if (checked) {
      card.classList.remove(...UNSELECTED);
      card.classList.add(...SELECTED);
    } else {
      card.classList.remove(...SELECTED);
      card.classList.add(...UNSELECTED);
    }
  }
}

// app/javascript/controllers/chat_panel_controller.ts
class ChatPanelController extends Controller {
  static targets = ['panel', 'backdrop', 'frame'];
  static values = { ordersUrl: String };
  open() {
    this.panelTarget.classList.remove('translate-x-full');
    this.backdropTarget.classList.remove('opacity-0', 'pointer-events-none');
    document.body.classList.add('overflow-hidden');
    this.frameTarget.src = this.ordersUrlValue;
  }
  close() {
    this.panelTarget.classList.add('translate-x-full');
    this.backdropTarget.classList.add('opacity-0', 'pointer-events-none');
    document.body.classList.remove('overflow-hidden');
  }
  toggle() {
    this.panelTarget.classList.contains('translate-x-full')
      ? this.open()
      : this.close();
  }
}

// app/javascript/controllers/chat_input_controller.ts
class ChatInputController extends Controller {
  static targets = ['fileInput', 'fileCount'];
  openFilePicker() {
    this.fileInputTarget.click();
  }
  filesChanged() {
    if (!this.hasFileCountTarget) return;
    const count = this.fileInputTarget.files?.length ?? 0;
    this.fileCountTarget.textContent = count > 0 ? String(count) : '';
    this.fileCountTarget.classList.toggle('hidden', count === 0);
  }
}

// app/javascript/controllers/color_picker_controller.ts
class ColorPickerController extends Controller {
  static targets = ['menu', 'colorDot', 'colorHex'];
  boundClose;
  connect() {
    this.boundClose = this.closeOutside.bind(this);
    document.addEventListener('click', this.boundClose);
  }
  disconnect() {
    document.removeEventListener('click', this.boundClose);
  }
  toggle(event) {
    event.stopPropagation();
    if (!this.hasMenuTarget) return;
    this.menuTarget.classList.toggle('hidden');
  }
  select(event) {
    const input = event.target;
    const hex = input.dataset.hex;
    if (hex) {
      this.colorDotTarget.style.backgroundColor = hex;
      this.colorHexTarget.textContent = hex;
    }
    this.menuTarget.classList.add('hidden');
  }
  closeOutside(event) {
    if (!this.hasMenuTarget) return;
    if (this.menuTarget.classList.contains('hidden')) return;
    if (!this.element.contains(event.target)) {
      this.menuTarget.classList.add('hidden');
    }
  }
}

// app/javascript/controllers/number_stepper_controller.ts
class NumberStepperController extends Controller {
  static targets = ['input'];
  increment() {
    const current = parseInt(this.inputTarget.value, 10) || 0;
    this.inputTarget.value = String(current + 1);
    this.inputTarget.dispatchEvent(new Event('change', { bubbles: true }));
  }
  decrement() {
    const current = parseInt(this.inputTarget.value, 10) || 0;
    const min = parseInt(this.inputTarget.min, 10);
    const next = isNaN(min) ? current - 1 : Math.max(min, current - 1);
    this.inputTarget.value = String(next);
    this.inputTarget.dispatchEvent(new Event('change', { bubbles: true }));
  }
}

// app/javascript/controllers/index.ts
application.register('color-picker', ColorPickerController);
application.register('number-stepper', NumberStepperController);
